{ title: "В аптеке с головной болью", scene: "После жаркого дня у моря у вас болит голова. Вы заходите в аптеку и объясняете проблему простыми словами.", lines: [{ who: "them", el: "Καλησπέρα σας.", ru: "Добрый вечер." }, { who: "you", el: "Καλησπέρα, χρειάζομαι βοήθεια.", ru: "Добрый вечер, мне нужна помощь." }, { who: "them", el: "Τι πρόβλημα έχετε;", ru: "Какая у вас проблема?" }, { who: "you", el: "Έχω πονοκέφαλο.", ru: "У меня болит голова." }, { who: "them", el: "Έχετε πυρετό;", ru: "У вас есть температура?" }, { who: "you", el: "Όχι, δεν έχω πυρετό.", ru: "Нет, температуры нет." }, { who: "them", el: "Έχετε αλλεργία σε φάρμακα;", ru: "У вас есть аллергия на лекарства?" }, { who: "you", el: "Όχι, δεν έχω αλλεργία.", ru: "Нет, у меня нет аллергии." }, { who: "them", el: "Πιείτε πολύ νερό και πάρτε αυτό.", ru: "Пейте много воды и возьмите это." }, { who: "you", el: "Πόσο κάνει;", ru: "Сколько стоит?" }, { who: "them", el: "Κάνει έξι ευρώ.", ru: "Это стоит шесть евро." }, { who: "you", el: "Ευχαριστώ πολύ.", ru: "Большое спасибо." }] },
{ title: "Небольшой разговор с местным жителем", scene: "Вы сидите в кафе в Салониках, и местный житель начинает дружелюбный разговор. Вы рассказываете, что вы впервые в Греции и вам нравится город.", lines: [{ who: "you", el: "Καλησπέρα, είναι ελεύθερη αυτή η θέση;", ru: "Добрый вечер, это место свободно?" }, { who: "them", el: "Ναι, βεβαίως.", ru: "Да, конечно." }, { who: "you", el: "Ευχαριστώ πολύ.", ru: "Большое спасибо." }, { who: "them", el: "Είστε τουρίστας;", ru: "Вы турист?" }, { who: "you", el: "Ναι, είμαι από τη Ρωσία.", ru: "Да, я из России." }, { who: "them", el: "Πρώτη φορά στην Ελλάδα;", ru: "Первый раз в Греции?" }, { who: "you", el: "Ναι, πρώτη φορά στην Ελλάδα.", ru: "Да, первый раз в Греции." }, { who: "them", el: "Σας αρέσει η Θεσσαλονίκη;", ru: "Вам нравится Салоники?" }, { who: "you", el: "Ναι, μου αρέσει πολύ η πόλη.", ru: "Да, мне очень нравится город." }, { who: "them", el: "Οι άνθρωποι εδώ είναι φιλικοί.", ru: "Люди здесь дружелюбные." }, { who: "you", el: "Ναι, και το φαγητό είναι πολύ νόστιμο.", ru: "Да, и еда очень вкусная." }, { who: "them", el: "Χαίρομαι, καλή διαμονή.", ru: "Я рад, хорошего пребывания." }] }
